const staticData = $getWorkflowStaticData('global');
if (!staticData.clients) staticData.clients = {};

const resp = $input.first().json;
const prev = $('Split Files').first().json;
const clientFolderName = prev.clientFolderName;

let parsed;
try {
  let rawText = resp.choices && resp.choices[0] ? resp.choices[0].message.content.trim() : '';
  const clean = rawText.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: { parseError: true, fileName: prev.fileName, fileId: prev.fileId,
    clientFolderId: prev.clientFolderId, clientFolderName, rawResponse: resp.choices ? resp.choices[0].message.content : JSON.stringify(resp), errorMessage: e.message }}];
}

const clientId = (parsed.client_id && String(parsed.client_id).trim()) || clientFolderName;
const date = parsed.date || "unbekannt";

if (!staticData.clients[clientId]) {
  staticData.clients[clientId] = { client_id: clientId, client_name: "", folderName: clientFolderName, operations: {} };
}
if (parsed.client_name && !staticData.clients[clientId].client_name) staticData.clients[clientId].client_name = parsed.client_name;
if (!staticData.clients[clientId].operations[date]) staticData.clients[clientId].operations[date] = {};

const FIELDS = ["Gewicht_kg","Grosse_cm","BMI_kg_m2","FM_kg","FM_pct","FMI_kg_m2","FFM_kg","FFM_pct","FFMI_kg_m2","SMM_kg","R_ohm","Xc_ohm","VAT_l","WC_cm","phase_angle_deg","perzentile","TBW_l","TBW_pct","ECW_l","ECW_pct","ECW_TBW_pct"];
const op = staticData.clients[clientId].operations[date];
for (const field of FIELDS) { if (parsed[field] !== null && parsed[field] !== undefined) op[field] = parsed[field]; }

return [{ json: { parseError: false, clientId, date, fileName: prev.fileName, fileId: prev.fileId, clientFolderId: prev.clientFolderId, clientFolderName }}];

const staticData = $getWorkflowStaticData('global');
const clients = staticData.clients || {};
const config = $('Set Config').first().json;

const clientList = Object.values(clients).filter(c => Object.keys(c.operations).length > 0);
if (!clientList.length) return [{ json: { empty: true } }];

const FIELD_ORDER = ["Gewicht_kg","Grosse_cm","BMI_kg_m2","FM_kg","FM_pct","FMI_kg_m2","FFM_kg","FFM_pct","FFMI_kg_m2","SMM_kg","R_ohm","Xc_ohm","VAT_l","WC_cm","phase_angle_deg","perzentile","TBW_l","TBW_pct","ECW_l","ECW_pct","ECW_TBW_pct"];

return clientList.map(c => {
  const sortedDates = Object.keys(c.operations).filter(d => d !== "unbekannt")
    .sort((a, b) => { const p = d => { const [dd,mm,yy] = d.split('.'); return new Date(yy, mm-1, dd); }; return p(a) - p(b); });
  if (c.operations["unbekannt"]) sortedDates.push("unbekannt");

  return { json: {
    clientId: c.client_id, clientName: c.client_name || '', folderName: c.folderName,
    operations: sortedDates.map((date, i) => ({ operationNumber: i+1, date, fields: c.operations[date] })),
    fieldOrder: FIELD_ORDER, totalOps: sortedDates.length,
    spreadsheetId: config.spreadsheetId, sheetGid: config.sheetGid, sheetName: config.sheetName,
    config
  }};
});

const sheetData = $input.first().json;
const prev = $('Split Clients Sheets').first().json;
const rows = sheetData.values || [];
const clientId = prev.clientId;
const clientName = prev.clientName;
const operations = prev.operations;
const FIELD_ORDER = prev.fieldOrder;
const sheetGid = prev.sheetGid;
const spreadsheetId = prev.spreadsheetId;
const sheetName = prev.sheetName;
const COLS_PER_OP = 21;
const START_COL = 2;

const headerRow = rows[1] || [];
let maxOpBlock = 0;
headerRow.forEach(cell => {
  const match = cell && String(cell).match(/^(\d+)\.\s*Operation/);
  if (match) maxOpBlock = Math.max(maxOpBlock, parseInt(match[1]));
});

const clientRowMap = {};
for (let i = 5; i < rows.length; i += 2) {
  const id = rows[i] && rows[i][0];
  if (id) clientRowMap[String(id).trim()] = i + 1;
}
const usedRows = Object.values(clientRowMap);
const nextFreeRow = usedRows.length > 0 ? Math.max(...usedRows) + 2 : 7;

let dateRow, dataRow;
if (clientRowMap[clientId]) { dateRow = clientRowMap[clientId]; dataRow = dateRow + 1; }
else { dateRow = nextFreeRow; dataRow = nextFreeRow + 1; }

const valueRanges = [];
const mergeRequests = [];

const SECTION_HEADERS = ['BMI','BMI','BMI','Fettmasse','Fettmasse','Fettmasse','Fettfreie Masse','Fettfreie Masse','Fettfreie Masse','Skelettmuskelmasse','BIVA','BIVA','Viszerales Fett & Taillenumfang','Viszerales Fett & Taillenumfang','Phasenwinkel','Phasenwinkel','Wasser','Wasser','Wasser','Wasser','Wasser'];
const FIELD_NAMES = ['Gewicht','Größe','BMI','FM','FM','FMI','FFM','FFM','FFMI','SMM','R','Xc','VAT','Taillenumfang','φ','Perzentile','TBW','TBW','ECW','ECW','ECW/TBW'];
const UNITS = ['kg','cm','kg/m²','kg','%','kg/m²','kg','%','kg/m²','kg','Ω','Ω','l','cm','°','—','l','%','l','%','%'];

function colToLetter(col) { let l=''; while(col>=0){l=String.fromCharCode(65+(col%26))+l;col=Math.floor(col/26)-1;} return l; }

// Headers for new op blocks
for (let opIdx = maxOpBlock; opIdx < operations.length; opIdx++) {
  const cs = START_COL + opIdx * COLS_PER_OP;
  const cl = colToLetter(cs); const ce = colToLetter(cs + COLS_PER_OP - 1);
  const r2 = new Array(COLS_PER_OP).fill(''); r2[0] = (opIdx+1)+'. Operation';
  valueRanges.push({range: sheetName+'!'+cl+'2:'+ce+'2', values: [r2]});
  valueRanges.push({range: sheetName+'!'+cl+'3:'+ce+'3', values: [SECTION_HEADERS]});
  valueRanges.push({range: sheetName+'!'+cl+'4:'+ce+'4', values: [FIELD_NAMES]});
  valueRanges.push({range: sheetName+'!'+cl+'5:'+ce+'5', values: [UNITS]});
  mergeRequests.push({mergeCells:{range:{sheetId:sheetGid,startRowIndex:1,endRowIndex:2,startColumnIndex:cs,endColumnIndex:cs+COLS_PER_OP},mergeType:"MERGE_ALL"}});
  [{s:0,c:3},{s:3,c:3},{s:6,c:3},{s:10,c:2},{s:12,c:2},{s:14,c:2},{s:16,c:5}].forEach(sec => {
    mergeRequests.push({mergeCells:{range:{sheetId:sheetGid,startRowIndex:2,endRowIndex:3,startColumnIndex:cs+sec.s,endColumnIndex:cs+sec.s+sec.c},mergeType:"MERGE_ALL"}});
  });
}

// Client data
const maxCols = START_COL + Math.max(operations.length, maxOpBlock) * COLS_PER_OP;
const dateVals = new Array(maxCols).fill('');
const dataVals = new Array(maxCols).fill('');
dateVals[0] = clientId; dateVals[1] = clientName;

operations.forEach((op, idx) => {
  const co = START_COL + idx * COLS_PER_OP;
  dateVals[co] = 'Datum der Operation: ' + op.date;
  FIELD_ORDER.forEach((field, fi) => {
    const v = op.fields[field];
    if (v !== undefined && v !== null) dataVals[co + fi] = v;
  });
  mergeRequests.push({mergeCells:{range:{sheetId:sheetGid,startRowIndex:dateRow-1,endRowIndex:dateRow,startColumnIndex:co,endColumnIndex:co+COLS_PER_OP},mergeType:"MERGE_ALL"}});
});

valueRanges.push({range:sheetName+'!A'+dateRow+':'+colToLetter(maxCols-1)+dateRow, values:[dateVals]});
valueRanges.push({range:sheetName+'!A'+dataRow+':'+colToLetter(maxCols-1)+dataRow, values:[dataVals]});

return [{ json: { spreadsheetId, sheetName, sheetGid, valueRanges, mergeRequests, clientId, clientFolderName: prev.folderName, clientFolderId: null }}];

