valueRanges.push({range:sheetName+'!A'+dateRow+':'+colToLetter(maxCols-1)+dateRow, values:[dateVals]});
valueRanges.push({range:sheetName+'!A'+dataRow+':'+colToLetter(maxCols-1)+dataRow, values:[dataVals]});

return [{ json: { spreadsheetId, sheetName, sheetGid, valueRanges, mergeRequests, clientId, clientFolderName: prev.folderName, clientFolderId: null }}];
